import { useEffect, useState } from "react";
import axios from "axios";
import profile from "../assets/nisha.jpeg";

function Portfolio() {
  const [stats, setStats] = useState({
    visitors: 0,
    projects: 0,
    resume: 0,
    logins: 0,
  });

  useEffect(() => {
    const loadStats = async () => {
      try {
        const res = await axios.get(
          "http://localhost:5000/api/analytics/stats",
        );
        setStats(res.data);
      } catch (err) {
        console.log("analytics error");
      }
    };

    axios.post("http://localhost:5000/api/analytics/visit", {
      page: "portfolio",
      browser: navigator.userAgent,
    });

    loadStats();
  }, []);

  return (
    <div
      style={{
        display: "flex",
        padding: "120px",
        gap: "80px",
      }}
    >
      {/* LEFT SIDE */}

      <div style={{ width: "300px", textAlign: "center" }}>
        <img
          src={profile}
          alt="Nisha"
          style={{
            width: "180px",
            height: "180px",
            borderRadius: "50%",
            objectFit: "cover",
          }}
        />

        <h2>Nisha Yadav</h2>

        <p>
          MERN Stack Developer passionate about building modern web applications
          using React, Node.js and MongoDB.
        </p>

        {/* ANALYTICS BELOW IMAGE */}

        <div style={{ marginTop: "30px" }}>
          <div style={cardStyle}>
            <h4>Visitors</h4>
            <p>{stats.visitors}</p>
          </div>

          <div style={cardStyle}>
            <h4>Project Clicks</h4>
            <p>{stats.projects}</p>
          </div>

          <div style={cardStyle}>
            <h4>Resume Downloads</h4>
            <p>{stats.resume}</p>
          </div>

          <div style={cardStyle}>
            <h4>Login History</h4>
            <p>{stats.logins}</p>
          </div>
        </div>
      </div>

      {/* RIGHT SIDE */}

      <div>
        <h2>Projects</h2>

        <button>AI Virtual Mouse</button>
        <br />
        <br />

        <button>AI Wardrobe</button>
        <br />
        <br />

        <button>Travel Booking App</button>
      </div>
    </div>
  );
}

const cardStyle = {
  border: "1px solid #ddd",
  padding: "10px",
  marginBottom: "10px",
  borderRadius: "8px",
  background: "#f5f5f5",
};

export default Portfolio;
